import React, { useState, useMemo } from 'react';

function runEarlyStopping(losses, patience, minDelta) {
  let bestLoss = Infinity;
  let bestEpoch = 0;
  let count = 0;
  const history = [];

  for (let epoch = 0; epoch < losses.length; epoch++) {
    const loss = losses[epoch];
    let improved = false;

    if (loss < bestLoss - minDelta) {
      bestLoss = loss;
      bestEpoch = epoch;
      count = 0;
      improved = true;
    } else {
      count++;
    }

    history.push({ epoch, loss, bestLoss: improved ? loss : bestLoss, bestEpoch, count, improved });

    if (count >= patience) {
      return { stopEpoch: epoch, bestEpoch, history, triggered: true };
    }
  }

  return { stopEpoch: losses.length - 1, bestEpoch, history, triggered: false };
}

const PRESETS = {
  classic: {
    name: 'Classic U-curve',
    losses: [0.90, 0.82, 0.75, 0.70, 0.67, 0.66, 0.67, 0.69, 0.72, 0.75]
  },
  noisy: {
    name: 'Noisy training',
    losses: [0.90, 0.82, 0.79, 0.77, 0.76, 0.78, 0.75, 0.77, 0.76, 0.78, 0.80]
  },
  plateau: {
    name: 'Slow plateau',
    losses: [0.90, 0.80, 0.75, 0.74, 0.738, 0.732, 0.729, 0.727, 0.726, 0.725]
  }
};

export default function App() {
  const [preset, setPreset] = useState('classic');
  const [patience, setPatience] = useState(2);
  const [minDelta, setMinDelta] = useState(0.01);
  const [hoveredEpoch, setHoveredEpoch] = useState(null);

  const losses = PRESETS[preset].losses;
  const result = useMemo(() => runEarlyStopping(losses, patience, minDelta), [losses, patience, minDelta]);
  const { stopEpoch, bestEpoch, history, triggered } = result;

  const W = 540, H = 195, padL = 42, padR = 18, padT = 28, padB = 30;
  const cW = W - padL - padR;
  const cH = H - padT - padB;

  const minL = Math.min(...losses) - 0.03;
  const maxL = Math.max(...losses) + 0.03;

  const toX = (i) => padL + (i / (losses.length - 1)) * cW;
  const toY = (l) => padT + (1 - (l - minL) / (maxL - minL)) * cH;

  const trainedPath = losses
    .slice(0, stopEpoch + 1)
    .map((l, i) => `${i === 0 ? 'M' : 'L'} ${toX(i).toFixed(1)} ${toY(l).toFixed(1)}`)
    .join(' ');

  const futurePath = losses
    .slice(stopEpoch)
    .map((l, i) => `${i === 0 ? 'M' : 'L'} ${toX(stopEpoch + i).toFixed(1)} ${toY(l).toFixed(1)}`)
    .join(' ');

  const hov = hoveredEpoch !== null ? history[hoveredEpoch] : null;
  const stepX = cW / (losses.length - 1);

  const patWindowStart = triggered ? bestEpoch + 1 : null;
  const patWindowEnd = triggered ? stopEpoch : null;

  return (
    <div style={{
      background: '#0a0a0a', minHeight: '100vh', display: 'flex',
      alignItems: 'center', justifyContent: 'center',
      fontFamily: "'JetBrains Mono', monospace", padding: '16px'
    }}>
      <div style={{ width: '100%', maxWidth: 580 }}>

        <div style={{ marginBottom: 12 }}>
          <h1 style={{ fontSize: 18, color: '#fafafa', margin: '0 0 2px', fontWeight: 700 }}>Early Stopping</h1>
          <p style={{ fontSize: 11, color: '#52525b', margin: 0 }}>
            Stop training when validation loss stops improving — save time, prevent overfitting
          </p>
        </div>

        {/* Preset buttons */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 10 }}>
          {Object.entries(PRESETS).map(([key, { name }]) => (
            <button key={key} onClick={() => { setPreset(key); setHoveredEpoch(null); }} style={{
              padding: '5px 11px', fontSize: 10, borderRadius: 6, border: 'none', cursor: 'pointer',
              background: preset === key ? '#8b5cf6' : '#1a1a1a',
              color: preset === key ? '#fafafa' : '#71717a',
              fontFamily: 'inherit', transition: 'all 0.2s', fontWeight: preset === key ? 700 : 400
            }}>{name}</button>
          ))}
        </div>

        {/* Hover info bar */}
        <div style={{
          background: '#111', borderRadius: '8px 8px 0 0', padding: '7px 14px',
          minHeight: 32, display: 'flex', alignItems: 'center', gap: 16, borderBottom: '1px solid #1a1a1a'
        }}>
          {hov ? (
            <>
              <span style={{ fontSize: 11, color: '#fafafa' }}>Epoch <b>{hov.epoch}</b></span>
              <span style={{ fontSize: 11, color: '#38bdf8' }}>loss: {hov.loss.toFixed(4)}</span>
              <span style={{ fontSize: 11, color: hov.improved ? '#4ade80' : '#fb923c' }}>
                {hov.improved ? 'improved (new best!)' : `no improvement (${hov.count}/${patience})`}
              </span>
              {hov.epoch > stopEpoch && (
                <span style={{ fontSize: 10, color: '#52525b', fontStyle: 'italic' }}>-- would-be epoch (not trained)</span>
              )}
            </>
          ) : (
            <span style={{ fontSize: 10, color: '#52525b', fontStyle: 'italic' }}>hover over a dot to inspect epoch</span>
          )}
        </div>

        {/* Main SVG chart */}
        <div style={{ background: '#111', borderRadius: '0 0 8px 8px', padding: '6px 6px 4px', marginBottom: 10 }}>
          <svg
            width="100%"
            viewBox={`0 0 ${W} ${H}`}
            style={{ display: 'block', cursor: 'crosshair' }}
            onMouseLeave={() => setHoveredEpoch(null)}
          >
            {/* Grid lines */}
            {[0, 0.25, 0.5, 0.75, 1].map(t => {
              const y = padT + t * cH;
              const val = maxL - t * (maxL - minL);
              return (
                <g key={t}>
                  <line x1={padL} y1={y} x2={padL + cW} y2={y} stroke="#1e1e1e" strokeWidth="1" />
                  <text x={padL - 5} y={y + 3.5} fontSize="9" fill="#3f3f46" textAnchor="end">{val.toFixed(2)}</text>
                </g>
              );
            })}

            {/* Y axis label */}
            <text x={10} y={padT + cH / 2} fontSize="9" fill="#3f3f46" textAnchor="middle"
              transform={`rotate(-90, 10, ${padT + cH / 2})`}>val loss</text>

            {/* Patience window shading */}
            {triggered && patWindowStart !== null && (
              <rect
                x={toX(patWindowStart) - stepX / 2}
                y={padT}
                width={toX(patWindowEnd) - toX(patWindowStart) + stepX}
                height={cH}
                fill="#a78bfa14"
                rx="2"
              />
            )}

            {/* Future (would-be) path */}
            {stopEpoch < losses.length - 1 && (
              <path d={futurePath} stroke="#27272a" strokeWidth="1.5" fill="none" strokeDasharray="4,3" />
            )}

            {/* Trained path */}
            <path d={trainedPath} stroke="#38bdf8" strokeWidth="2.5" fill="none" strokeLinejoin="round" />

            {/* Best epoch vertical line */}
            <line
              x1={toX(bestEpoch)} y1={padT}
              x2={toX(bestEpoch)} y2={padT + cH}
              stroke="#4ade80" strokeWidth="1.5" strokeDasharray="4,3" opacity="0.7"
            />

            {/* Stop epoch vertical line */}
            {triggered && (
              <line
                x1={toX(stopEpoch)} y1={padT}
                x2={toX(stopEpoch)} y2={padT + cH}
                stroke="#f87171" strokeWidth="1.5" strokeDasharray="4,3" opacity="0.8"
              />
            )}

            {/* Patience bracket */}
            {triggered && patWindowStart !== null && (
              <>
                <line
                  x1={toX(patWindowStart)} y1={padT + cH + 8}
                  x2={toX(patWindowEnd)} y2={padT + cH + 8}
                  stroke="#a78bfa" strokeWidth="1.5"
                />
                <line x1={toX(patWindowStart)} y1={padT + cH + 4} x2={toX(patWindowStart)} y2={padT + cH + 12} stroke="#a78bfa" strokeWidth="1.5" />
                <line x1={toX(patWindowEnd)} y1={padT + cH + 4} x2={toX(patWindowEnd)} y2={padT + cH + 12} stroke="#a78bfa" strokeWidth="1.5" />
                <text
                  x={(toX(patWindowStart) + toX(patWindowEnd)) / 2}
                  y={padT + cH + 22}
                  fontSize="8" fill="#a78bfa" textAnchor="middle"
                >patience={patience}</text>
              </>
            )}

            {/* Epoch dots + invisible hit areas */}
            {losses.map((l, i) => {
              const isFuture = i > stopEpoch;
              const isStop = triggered && i === stopEpoch;
              const isBest = i === bestEpoch;
              const inPatience = triggered && i > bestEpoch && i <= stopEpoch;
              const isHov = i === hoveredEpoch;

              const col = isFuture ? '#27272a'
                : isBest ? '#4ade80'
                : isStop ? '#f87171'
                : inPatience ? '#fb923c'
                : '#38bdf8';

              const r = isHov ? 7 : (isStop || isBest) ? 6 : isFuture ? 3.5 : 4.5;

              return (
                <g key={i}
                  onMouseEnter={() => setHoveredEpoch(i)}
                  style={{ cursor: 'pointer' }}
                >
                  <circle
                    cx={toX(i)} cy={toY(l)} r={14}
                    fill="transparent"
                  />
                  <circle
                    cx={toX(i)} cy={toY(l)} r={r}
                    fill={col}
                    opacity={isFuture ? 0.35 : 1}
                    style={{ transition: 'r 0.15s, opacity 0.15s' }}
                  />
                  {isBest && (
                    <text x={toX(i)} y={toY(l) - 10} fontSize="8" fill="#4ade80" textAnchor="middle" fontWeight="700">best</text>
                  )}
                  {isStop && triggered && (
                    <text x={toX(i)} y={toY(l) - 10} fontSize="8" fill="#f87171" textAnchor="middle" fontWeight="700">stop</text>
                  )}
                </g>
              );
            })}

            {/* X-axis epoch labels */}
            {losses.map((_, i) => (
              <text key={i} x={toX(i)} y={H - 4} fontSize="9" fill="#3f3f46" textAnchor="middle">{i}</text>
            ))}
          </svg>
        </div>

        {/* Legend */}
        <div style={{ display: 'flex', gap: 14, marginBottom: 10, flexWrap: 'wrap' }}>
          {[
            { col: '#4ade80', label: `best epoch (${bestEpoch})` },
            { col: '#f87171', label: triggered ? `stop epoch (${stopEpoch})` : 'stop (not triggered)' },
            { col: '#fb923c', label: 'no improvement' },
            { col: '#27272a', label: 'wasted epochs', dashed: true }
          ].map(({ col, label, dashed }) => (
            <span key={label} style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 10, color: '#71717a' }}>
              {dashed
                ? <span style={{ width: 16, height: 2, background: col, display: 'inline-block', borderTop: '2px dashed #52525b' }} />
                : <span style={{ width: 9, height: 9, borderRadius: '50%', background: col, display: 'inline-block' }} />}
              {label}
            </span>
          ))}
        </div>

        {/* Controls */}
        <div style={{ background: '#111', borderRadius: 10, padding: '12px 14px', marginBottom: 10 }}>
          <div style={{ display: 'flex', gap: 20, flexWrap: 'wrap' }}>
            <div style={{ flex: 1, minWidth: 200 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 5 }}>
                <span style={{ fontSize: 11, color: '#94a3b8' }}>patience (epochs to wait)</span>
                <span style={{ fontSize: 14, color: '#8b5cf6', fontWeight: 700 }}>{patience}</span>
              </div>
              <input
                type="range" min="1" max="6" step="1" value={patience}
                onChange={e => { setPatience(+e.target.value); setHoveredEpoch(null); }}
                style={{ width: '100%', accentColor: '#8b5cf6', cursor: 'pointer' }}
              />
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: '#3f3f46', marginTop: 2 }}>
                <span>1 (aggressive)</span><span>6 (lenient)</span>
              </div>
            </div>

            <div style={{ flex: 1, minWidth: 200 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 5 }}>
                <span style={{ fontSize: 11, color: '#94a3b8' }}>min_delta (min improvement)</span>
                <span style={{ fontSize: 14, color: '#8b5cf6', fontWeight: 700 }}>{minDelta.toFixed(3)}</span>
              </div>
              <input
                type="range" min="0" max="0.06" step="0.005" value={minDelta}
                onChange={e => { setMinDelta(+e.target.value); setHoveredEpoch(null); }}
                style={{ width: '100%', accentColor: '#8b5cf6', cursor: 'pointer' }}
              />
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: '#3f3f46', marginTop: 2 }}>
                <span>0 (any drop counts)</span><span>0.06 (big drops only)</span>
              </div>
            </div>
          </div>
        </div>

        {/* Insight */}
        <div style={{
          background: '#111', borderRadius: 8, padding: '10px 14px',
          borderLeft: `3px solid ${triggered ? '#8b5cf6' : '#fbbf24'}`
        }}>
          <div style={{ fontSize: 12, color: '#94a3b8', lineHeight: 1.6 }}>
            {triggered ? (
              <>
                <span style={{ color: '#f87171', fontWeight: 700 }}>Stopped at epoch {stopEpoch}.</span>
                {' '}Loss hadn't dropped by more than <span style={{ color: '#8b5cf6' }}>{minDelta.toFixed(3)}</span> for{' '}
                <span style={{ color: '#a78bfa' }}>{patience} epochs</span> in a row.{' '}
                Best model was epoch <span style={{ color: '#4ade80', fontWeight: 700 }}>{bestEpoch}</span>{' '}
                (loss <span style={{ color: '#4ade80' }}>{losses[bestEpoch].toFixed(4)}</span>).{' '}
                {stopEpoch < losses.length - 1 && (
                  <span style={{ color: '#fb923c' }}>Saved {losses.length - 1 - stopEpoch} unnecessary epochs.</span>
                )}
              </>
            ) : (
              <>
                <span style={{ color: '#fbbf24', fontWeight: 700 }}>No early stopping triggered</span> — training ran all {losses.length} epochs.
                {' '}Try lowering patience or raising min_delta to see it stop sooner.
              </>
            )}
          </div>
        </div>

      </div>
    </div>
  );
}
